mapper.select:
		select approvalid, approvalname, seq, phase 
          from cotdl.tbl_piiapproval
          where approvalid= #{approvalid, jdbcType=VARCHAR}

		select approvalid, approvalname, seq, approverid, approvername 
          from cotdl.tbl_piiapprovaluser
          where approvalid= #{approvalid, jdbcType=VARCHAR}

mapper.update:
update cotdl.tbl_piiapprovalreq
set
	approverid= #{approverid, jdbcType=VARCHAR},
	approvername= #{approvername, jdbcType=VARCHAR},
	reqreason= #{reqreason, jdbcType=VARCHAR}
where reqid= #{reqid, jdbcType=VARCHAR}
